window.__QUIZ_DATA__=[{"id":"objective>Commerce>1994>1","subject":"Commerce","year":"1994","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"Which of the following is not true of commerce?","images":[],"options":{"A":"It is part of production","B":"It creates time and place utility","C":"It is the life blood of a nation's economic activities","D":"Commercialization activities began after the goods are produced"},"answer":"A","explanation":"The statement 'It is part of production' is not true of commerce. Commerce is primarily concerned with the distribution and sale of goods and services, while production refers to the creation of goods. Therefore, commerce does not directly involve the production process.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>2","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"Capital owned is the same as","images":[],"options":{"A":"authorised capital","B":"issued capital","C":"net worth of a business","D":"fixed assets of a business"},"answer":"C","explanation":"Capital owned refers to the net worth of a business, which is the total assets minus total liabilities. This is a measure of the financial health of a business and indicates the owner's equity in the business.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>3","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES","question":"A business that has no upper limit to the number of owners is","images":[],"options":{"A":"partnership","B":"private company","C":"finance company","D":"public limited company"},"answer":"D","explanation":"A public limited company is a business that can have an unlimited number of owners (shareholders). This type of company can sell shares to the public, which allows for a larger pool of capital and ownership.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>4","subject":"Commerce","year":"1994","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT","question":"An agreement between two parties which can be enforced is called","images":[],"options":{"A":"an agency","B":"a contract","C":"a consideration","D":"an offer"},"answer":"B","explanation":"An agreement between two parties that can be enforced by law is called a contract. Contracts are legally binding agreements that outline the rights and obligations of the parties involved.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>5","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"Which of the following terms related to insurance?    I. Proximate cause  II. Letter of hypothecation  III. Indemnity  IV. Caveat emptor  V. Uberimae fidei","images":[],"options":{"A":"I, II and IV only","B":"II, IV and V only","C":"I, III and V only","D":"II, III and V only"},"answer":"C","explanation":"The terms related to insurance are proximate cause, indemnity, and uberimae fidei. Proximate cause refers to the primary cause of a loss, indemnity is the principle that ensures a policyholder is compensated for their loss without profit, and uberimae fidei means utmost good faith, which is a fundamental principle in insurance contracts.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1994>6","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following is not used by the Central Bank to restrict lending by commercial banks?","images":[],"options":{"A":"Management of national debt","B":"Reserve Requirement","C":"Open Market Operations","D":"Cash Ratio"},"answer":"D","explanation":"The Cash Ratio is not typically used by the Central Bank to restrict lending by commercial banks. Instead, it is a measure of the amount of cash that banks must hold against their deposits. The other options, such as Management of national debt, Reserve Requirement, Open Market Operations, and Special Deposit, are all tools used by Central Banks to control the money supply and influence lending.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1994>7","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"Which of the following relies on the government for  its initial capital ?","images":[],"options":{"A":"Co-operative Society","B":"Private Limited Company","C":"Public Corporation","D":"Public Limited Company"},"answer":"C","explanation":"A Public Corporation relies on the government for its initial capital. Public Corporations are typically established by the government to provide services or goods that are deemed essential for the public. They are funded by government resources, unlike Private Limited Companies or Public Limited Companies, which rely on private investment.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>8","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : TYPES OF BANK","question":"A cheque does not contain","images":[],"options":{"A":"cheque number","B":"cashier's signature","C":"payee's name","D":"drawee's name"},"answer":"B","explanation":"A cheque does not contain the cashier's signature. A cheque typically includes the cheque number, payee's name, drawee's name, and date of issue. The cashier's signature is not a standard requirement for a cheque; instead, it is usually signed by the account holder.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>9","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"The most acceptance and convenient means of payment in foreign trade is","images":[],"options":{"A":"letter of credit","B":"bank-draft","C":"telegraphic money order","D":"promissory note"},"answer":"A","explanation":"The most accepted and convenient means of payment in foreign trade is a letter of credit. A letter of credit is a document issued by a bank guaranteeing payment to a seller, provided that the seller meets the terms and conditions specified in the letter. It is widely used in international trade to mitigate risks.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>10","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TYPES","question":"An establishment that specialises in taking care of  risks is called","images":[],"options":{"A":"a hire-purchase company","B":"an accepting house","C":"an insurance company","D":"a finance company"},"answer":"C","explanation":"An establishment that specializes in taking care of risks is called an insurance company. Insurance companies provide financial protection against various risks by pooling resources from policyholders and compensating them in case of loss or damage. This is a fundamental concept in risk management.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>11","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"An association of firms, producing similar commodities , formed in order to keep up prices by restricting output is called","images":[],"options":{"A":"a chamber of commerce","B":"a customers union","C":"an amalgamation","D":"a cartel"},"answer":"D","explanation":"The correct term for an association of firms that produce similar commodities and aim to keep prices stable by restricting output is a 'cartel'. A cartel is a formal agreement among competing firms to control prices or limit production, which can lead to higher prices for consumers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>12","subject":"Commerce","year":"1994","type":"Objective","topic":"OCCUPATION : TYPES OF OCCUPATION","question":"Which of the following is an example of a commercial occupation?","images":[],"options":{"A":"Wrestling","B":"Welding","C":"Shipping","D":"Brick laying"},"answer":"C","explanation":"Shipping is a commercial occupation as it involves the transportation of goods for trade. It is a key component of commerce, facilitating the movement of products from producers to consumers.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>13","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION","question":"Which of the following should be considered when transporting fragile and perishable goods?    I. Speed  II. Cost  III. Safety  IV. Flexibility  V. Convenience","images":[],"options":{"A":"I and II only","B":"III, IV and V only","C":"I, III and IV only","D":"I, III and V only"},"answer":"C","explanation":"When transporting fragile and perishable goods, speed, safety, and flexibility are crucial. Speed ensures that goods reach their destination quickly to prevent spoilage, safety protects the goods during transit, and flexibility allows for adjustments in transport methods as needed.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>14","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Which of the following carries the bulk of goods involved in foreign trade?","images":[],"options":{"A":"Cargo planes","B":"Cargo liners","C":"Tramp vessels","D":"Steam ship"},"answer":"B","explanation":"Cargo liners are vessels specifically designed for the transportation of goods in bulk, particularly in foreign trade. They operate on fixed routes and schedules, making them a primary means of transporting large quantities of goods internationally.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>15","subject":"Commerce","year":"1994","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"A stock exchange is a market for","images":[],"options":{"A":"old stocks of goods","B":"capital goods only","C":"raising new shares","D":"existing shares of quoted companies"},"answer":"D","explanation":"A stock exchange is primarily a market for existing shares of quoted companies. It facilitates the buying and selling of shares that are already in circulation, providing liquidity to investors and enabling price discovery.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>16","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"Which of the following gives a temporary protection to the insured while the policy is being drawn up?","images":[],"options":{"A":"Proposal form","B":"Cover note","C":"Endorsement","D":"Ex gratia payment"},"answer":"B","explanation":"A cover note is a temporary document issued by an insurance company that provides proof of insurance coverage until the actual policy is finalized. It serves as a temporary protection for the insured while the policy is being drawn up.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>17","subject":"Commerce","year":"1994","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE","question":"Which of the following is not a function of management?","images":[],"options":{"A":"Staffing","B":"Planning","C":"Organising","D":"Distribution"},"answer":"D","explanation":"Distribution is not typically considered a core function of management. The primary functions of management include staffing, planning, organizing, and directing. Distribution is more related to logistics and marketing rather than management itself.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>18","subject":"Commerce","year":"1994","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Which of the following is responsible for the welfare of staff in an organisation?","images":[],"options":{"A":"Accounts Department","B":"Administrative Department","C":"Personnel Department","D":"Sales Department"},"answer":"C","explanation":"The Personnel Department, also known as Human Resources, is responsible for the welfare of staff in an organization. This department handles employee relations, benefits, training, and overall employee well-being.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>19","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES","question":"Which of th following is not a marketing function?","images":[],"options":{"A":"Packaging","B":"Branding","C":"Advertising","D":"Accounting"},"answer":"D","explanation":"Accounting is not a marketing function. Marketing functions typically include activities related to promoting and selling products, such as packaging, branding, advertising, and pricing. Accounting focuses on financial record-keeping and reporting.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>20","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES","question":"Which of the following is not an aim of advertising?","images":[],"options":{"A":"drive away smaller firms","B":"satisfy consumers","C":"help firms compete with others","D":"make one's product known"},"answer":"A","explanation":"Driving away smaller firms is not an aim of advertising. The primary aims of advertising include satisfying consumers, helping firms compete, making products known, and increasing sales. Advertising is intended to promote products and services positively, not to harm competitors.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>21","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES","question":"In which of the following environments does a firm that uses out-dated equipment operate?","images":[],"options":{"A":"Economic","B":"Technological","C":"Social","D":"Political"},"answer":"B","explanation":"A firm that uses outdated equipment operates in a 'Technological' environment. The technological environment refers to the state of technology and innovation that affects how businesses operate. Outdated equipment indicates that the firm is not keeping up with technological advancements, which can impact efficiency and competitiveness.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>22","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following is sent when credit is not allowed?","images":[],"options":{"A":"Debit note","B":"Proforma invoice","C":"Credit note","D":"Statement"},"answer":"A","explanation":"When credit is not allowed, a 'Debit note' is sent. A debit note is a document issued by a buyer to a seller, indicating that a certain amount has been debited to the seller's account. It is used when goods are returned or when there is a need to adjust the amount owed, especially when credit terms are not applicable.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>23","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: SOLE PROPRIETORSHIP : MEANING AND IMPORTANCE","question":"Which of the following does not determine the form of a business unit?","images":[],"options":{"A":"Available capital","B":"Risk bearing","C":"Nearness to market","D":"Ownership"},"answer":"C","explanation":"While available capital, risk bearing, ownership, and nature of business are all factors that influence the structure of a business, 'Neareness to market' does not inherently determine the form of a business unit. It may affect operational decisions but is not a foundational determinant.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>24","subject":"Commerce","year":"1994","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT","question":"Agents who link buyers with sellers receive","images":[],"options":{"A":"factorage","B":"brokerage","C":"bonus","D":"interest"},"answer":"B","explanation":"Agents who link buyers with sellers receive 'brokerage'. Brokerage is a fee or commission paid to an agent or broker for facilitating a transaction between two parties. This is a common practice in various industries, including real estate and finance.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>25","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Which of the following is not a feature of supermarkets?","images":[],"options":{"A":"Standard shop fronts","B":"Self service","C":"Use of trolleys","D":"Small number of sales assistants"},"answer":"D","explanation":"A feature that is not characteristic of supermarkets is 'Small number of sales assistants'. Supermarkets typically employ a large number of sales assistants to manage the self-service model and assist customers, which contrasts with the option provided.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>26","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Which of the following is an objectives of indigenisation? To","images":[],"options":{"A":"increase foreign participation in business","B":"attract foreign capital","C":"help Nigerian entrepreneurs become monopolists","D":"help citizens participate fully in the economy"},"answer":"D","explanation":"The objective of indigenisation is to help citizens participate fully in the economy. This involves empowering local entrepreneurs and businesses to take part in economic activities, thereby reducing reliance on foreign entities.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>27","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"In which of the following are the objectives of a company stated?","images":[],"options":{"A":"Annual Report","B":"Articles of Association","C":"Certificate of Incorporation","D":"Memorandum of Association"},"answer":"D","explanation":"The objectives of a company are typically stated in the Memorandum of Association. This document outlines the company's purpose, the scope of its activities, and the powers it has to achieve its objectives.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>28","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"The coming together of firms at different stages of the production is known as","images":[],"options":{"A":"horizontal integration","B":"vertical integration","C":"consortium","D":"cartel"},"answer":"B","explanation":"The coming together of firms at different stages of production is known as vertical integration. This strategy allows companies to control more of their supply chain, from raw materials to final product distribution.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>29","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE","question":"The storing of goods under proper conditions until they are required is a function of","images":[],"options":{"A":"stock taking","B":"warehousing","C":"stock control","D":"merchandising"},"answer":"B","explanation":"The storing of goods under proper conditions until they are required is a function of warehousing. Warehousing involves the storage of goods in a facility designed to protect them until they are needed for distribution or sale.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>30","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER","question":"Rate of turnover is the","images":[],"options":{"A":"number of times opening stock is sold during a period","B":"rate paid by retailers stocks","C":"rate paid to agents for turn","D":"number of times average stock is sold during a period"},"answer":"D","explanation":"Rate of turnover refers to the number of times average stock is sold during a period. It is a measure of how efficiently a company is managing its inventory and generating sales.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>31","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"A postal order, either crossed or open is only valid for a period of","images":[],"options":{"A":"12 months","B":"10 months","C":"8 months","D":"6 months"},"answer":"A","explanation":"A postal order, whether crossed or open, is valid for a period of 12 months. This is a standard duration for postal orders to ensure that they are used within a reasonable timeframe.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>32","subject":"Commerce","year":"1994","type":"Objective","topic":"NATIONALIZATION AND PRIVATIZATION","question":"The process of taking over private business by government is known as","images":[],"options":{"A":"naturalisation","B":"nationalisation","C":"privatisation","D":"commercialisation"},"answer":"B","explanation":"The process of taking over private business by the government is known as nationalisation. This involves the transfer of ownership from private to public sector, often to control key industries or services for the public good.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>33","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE ASSOCIATION : MEANING & FUNCTIONS","question":"Which of the following is not the objective of Consumer Association? To","images":[],"options":{"A":"ensure that fair prices are charged","B":"educate consumers on their rights","C":"prevent fake goods from entering the market","D":"ensure correct specifications as to quality of goods"},"answer":"D","explanation":"Ensuring correct specifications as to quality of goods is not typically an objective of Consumer Associations. Their main goals include ensuring fair pricing, educating consumers, preventing fake goods, and advocating for consumer protection laws.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>34","subject":"Commerce","year":"1994","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF TRADE","question":"Zaico Ltd invoiced goods valued at #80,000 to Victory Ltd for #8,000. Which of the following will Zaico Ltd send to Victory Ltd to correct the error?","images":[],"options":{"A":"Consignment note","B":"Credit note","C":"Advice note","D":"Debit note"},"answer":"B","explanation":"To correct the error in invoicing, Zaico Ltd would send a Credit note to Victory Ltd. A Credit note is issued to reduce the amount owed by the buyer, typically used when there has been an overcharge or error in the original invoice.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>35","subject":"Commerce","year":"1994","type":"Objective","topic":"PRODUCTION : MEANING & IMPORTANCE","question":"Which of the following is an example of extractive industry?","images":[],"options":{"A":"Sewing dresses","B":"Constructing bridges","C":"Baking bread","D":"Digging for precious stones"},"answer":"D","explanation":"Digging for precious stones is an example of an extractive industry. Extractive industries involve the extraction of natural resources from the earth, such as mining for minerals, oil, and gas.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>36","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"The raising of new capital by allowing existing shareholders the privilege to buy shares at preferential rate is called","images":[],"options":{"A":"bonus issue","B":"private placing","C":"offer for sale","D":"rights issue"},"answer":"D","explanation":"The correct term for raising new capital by allowing existing shareholders the privilege to buy shares at a preferential rate is called a 'rights issue'. This process allows current shareholders to purchase additional shares at a discounted price before the shares are offered to the public, thus giving them the first opportunity to maintain their proportional ownership in the company.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>37","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"The agreed amount payable to a policy holder when the event insured against occurs is","images":[],"options":{"A":"surrender value","B":"sum assured","C":"indemnity","D":"insurable interest"},"answer":"B","explanation":"The agreed amount payable to a policyholder when the event insured against occurs is known as the 'sum assured'. This is the amount that the insurer agrees to pay upon the occurrence of the insured event, such as death or total disability, as specified in the insurance policy.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>38","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"The rate at which one country's products are exchanged for the products of another is","images":[],"options":{"A":"balance of trade","B":"balance on current account","C":"terms of trade","D":"balance of payments"},"answer":"C","explanation":"The rate at which one country's products are exchanged for the products of another is referred to as the 'terms of trade'. This concept measures the relative prices of exports to imports and indicates the economic health of a country in terms of its trade relationships.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>39","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"Which of the following is not performed by the shipping and forwarding agents?","images":[],"options":{"A":"Reservation of shipping space","B":"Collection of payment from the importer","C":"Collection of goods from the factory","D":"Preparation of the bill of lading"},"answer":"B","explanation":"Shipping and forwarding agents typically do not collect payment from the importer; this task is usually handled by the seller or a financial institution. Their primary roles include reserving shipping space, preparing bills of lading, and arranging for marine insurance, among other logistical tasks.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>40","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE ASSOCIATION : MEANING & FUNCTIONS","question":"A group of firms that produce similar goods or services is called","images":[],"options":{"A":"an industry","B":"a trade association","C":"a cartel","D":"a holding company"},"answer":"A","explanation":"A group of firms that produce similar goods or services is called 'an industry'. An industry encompasses all businesses that produce similar products or services, and it is a broader term than a trade association or cartel, which may represent specific interests within that industry.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>41","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"Retail outlets which sell from specialised vans are","images":[],"options":{"A":"supermarkets","B":"multiple shops","C":"mail order firms","D":"mobile shops"},"answer":"D","explanation":"Retail outlets that sell from specialized vans are referred to as 'mobile shops'. These are vehicles that are equipped to sell goods directly to consumers, often in various locations.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>42","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : SERVICES","question":"Which of the following is a problem facing mail order business?","images":[],"options":{"A":"Expensive shop fronts","B":"Cost of postage and advertisement","C":"Commission to agents","D":"Increase in branded goods"},"answer":"B","explanation":"A significant problem facing mail order businesses is the 'Cost of postage and advertisement'. These costs can be substantial and impact the overall profitability of the business, as they are necessary for reaching customers and delivering products.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>43","subject":"Commerce","year":"1994","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF TRADE","question":"When the exporter arranges for the despatch of goods but leaves the cost of transport to be paid by the importer, the price quoted is","images":[],"options":{"A":"carriage forward","B":"franco","C":"loco","D":"free on board"},"answer":"A","explanation":"When the exporter arranges for the dispatch of goods but leaves the cost of transport to be paid by the importer, the price quoted is known as 'carriage forward'. This means that the buyer is responsible for the shipping costs once the goods are dispatched.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>44","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"The practice of selling, goods in foreign countries at lower prices than obtainable in the exporting country is known as","images":[],"options":{"A":"hedging","B":"black market","C":"dumping","D":"speculation"},"answer":"C","explanation":"The practice of selling goods in foreign countries at lower prices than obtainable in the exporting country is known as 'dumping'. This can be a strategy used to gain market share in a foreign market by undercutting local prices.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>45","subject":"Commerce","year":"1994","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"The process of entrusting part of the work of a superior and the corresponding authority to a subordinate in an organisation is called","images":[],"options":{"A":"delegation","B":"deputising","C":"coordinating","D":"supervision"},"answer":"A","explanation":"The process of entrusting part of the work of a superior and the corresponding authority to a subordinate in an organization is called 'delegation'. This is a key management skill that allows for more efficient operation and development of employees.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>46","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : TYPES OF BANK","question":"Which of the following is not considered by banks when granting loans to customers?","images":[],"options":{"A":"Character of the customer","B":"Period of business","C":"Amount needed","D":"Period of repayment"},"answer":"A","explanation":"The factor not considered by banks when granting loans is Character of the customer. Period of repayment, Amount needed, Purpose of the loan are typically considered by banks.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>47","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.","question":"Import duty imposed on a commodity according to the quantity imported is","images":[],"options":{"A":"ad valorem duty","B":"customs duty","C":"excise duty","D":"specific duty"},"answer":"D","explanation":"Import duty imposed on a commodity according to the quantity imported is known as 'specific duty'. This type of duty is calculated based on a fixed amount per unit of the imported good, rather than a percentage of its value, which distinguishes it from ad valorem duty.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>48","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : TYPES OF BANK","question":"A cheque that is drawn on a bank is called","images":[],"options":{"A":"certified cheque","B":"bank draft","C":"bank note","D":"order cheque"},"answer":"D","explanation":"A cheque that is drawn on a bank is called an 'order cheque'. This type of cheque is payable to a specific person or entity and requires the bank to pay the amount specified to the person named on the cheque.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>49","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Which of the following forms of transport moves crude oil to the ports for export?","images":[],"options":{"A":"Rail","B":"Pipeline","C":"Road","D":"Air"},"answer":"B","explanation":"The form of transport that moves crude oil to the ports for export is 'Pipeline'. Pipelines are specifically designed for the efficient and safe transportation of liquids, including crude oil, over long distances.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>50","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES","question":"The rebate given to the retailer by the wholesaler to enable him to make profit is known as","images":[],"options":{"A":"trade discount","B":"cash discount","C":"credit guarantee","D":"commission"},"answer":"A","explanation":"The rebate given to the retailer by the wholesaler to enable him to make a profit is known as 'trade discount'. This discount is provided to incentivize retailers to purchase goods in bulk and is typically deducted from the invoice price.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>51","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Who among the following is not involved in foreign trade?","images":[],"options":{"A":"Factor","B":"Del Credere Agent","C":"Wholesale Merchant","D":"Jobber"},"answer":"A","explanation":"A 'Factor' is a financial intermediary that buys receivables from businesses and provides immediate cash. They are involved in trade finance but not directly in foreign trade. The other options (Del Credere Agent, Wholesale Merchant, Jobber, Forwarding Agent) are all involved in facilitating or executing foreign trade transactions.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>52","subject":"Commerce","year":"1994","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"Which of the following belongs to the capital market?","images":[],"options":{"A":"Commercial bank","B":"Stock exchange","C":"Ministry of Finance","D":"Chamber of Commerce"},"answer":"B","explanation":"The 'Stock exchange' is a platform where securities, including stocks and bonds, are bought and sold, making it a key component of the capital market. The other options (Commercial bank, Ministry of Finance, Chamber of Commerce, Discount House) do not directly represent the capital market.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>53","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE","question":"The giving of clear instructions and information to all concerned in an organisation to ensure proper understanding of decisions and policies is","images":[],"options":{"A":"organising","B":"planning","C":"communicating","D":"directing"},"answer":"C","explanation":"The process of 'communicating' involves giving clear instructions and information to ensure that all members of an organization understand decisions and policies. This is essential for effective management and coordination within an organization.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>54","subject":"Commerce","year":"1994","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"Commerce is not concerned with","images":[],"options":{"A":"changing the place of a product","B":"changing the form of a product","C":"changing ownership of a product","D":"warehousing of a product"},"answer":"D","explanation":"Commerce is primarily concerned with the exchange of goods and services, which includes changing ownership, distribution, and warehousing. However, 'warehousing of a product' is more about storage rather than the actual commerce process, which focuses on the transaction and movement of goods.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>55","subject":"Commerce","year":"1994","type":"Objective","topic":"STOCK EXCHANGE : TYPES OF SECURITIES","question":"An alternative term for ordinary shares is","images":[],"options":{"A":"unit trust","B":"gilt-edged securities","C":"equities","D":"bonus issues"},"answer":"C","explanation":"The term 'equities' is commonly used as an alternative term for ordinary shares. Equities represent ownership in a company, while the other options refer to different financial instruments or investment vehicles.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>56","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"The retail of goods through currency operated machines is known as","images":[],"options":{"A":"mail order business","B":"automatic vending","C":"party selling","D":"impulse buying"},"answer":"B","explanation":"The retail of goods through currency operated machines is known as automatic vending. Automatic vending refers to the use of machines that dispense products when a customer inserts currency or a card. This method allows for quick and convenient access to goods without the need for human interaction.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>57","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA","question":"Any paid form of non-personal presentation of ideas, goods or services by an identified sponsor is known as","images":[],"options":{"A":"market research","B":"market orientation","C":"open market operation","D":"advertising"},"answer":"D","explanation":"Any paid form of non-personal presentation of ideas, goods or services by an identified sponsor is known as advertising. Advertising is a marketing communication that aims to promote products or services to consumers through various media channels, and it is typically paid for by the sponsor.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>58","subject":"Commerce","year":"1994","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE","question":"The art of achieving stated objectives of a business organisation in a most efficient way through the use of human and material resources is","images":[],"options":{"A":"planning","B":"co-ordinating","C":"management","D":"motivation"},"answer":"C","explanation":"The art of achieving stated objectives of a business organisation in a most efficient way through the use of human and material resources is known as management. Management involves planning, organizing, leading, and controlling an organization's resources to achieve specific goals effectively and efficiently.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>59","subject":"Commerce","year":"1994","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"Which of the following encourages free trade among member nations?","images":[],"options":{"A":"IMF","B":"UNO","C":"WHO","D":"EEC"},"answer":"D","explanation":"The organization that encourages free trade among member nations is the EEC (European Economic Community). The EEC was established to promote economic integration and free trade among its member states, facilitating the movement of goods, services, and capital.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>60","subject":"Commerce","year":"1994","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"ECOWAS headquarters is located in","images":[],"options":{"A":"Ghana","B":"Nigeria","C":"Senegal","D":"Sierra Leone"},"answer":"B","explanation":"ECOWAS (Economic Community of West African States) headquarters is located in Nigeria. ECOWAS is a regional political and economic union of fifteen countries located in West Africa, and its headquarters is situated in Abuja, Nigeria.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>61","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Which of the following refers to the practice of importing for re-export?","images":[],"options":{"A":"Counter trade","B":"Dumping","C":"Entreport trade","D":"Forward trading"},"answer":"C","explanation":"The practice of importing goods for the purpose of re-exporting them is known as 'Entreport trade'. This involves bringing goods into a country and then exporting them again, often with some processing or value addition. This is distinct from other trade practices like counter trade or dumping.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>62","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"Firms merge in order to","images":[],"options":{"A":"discourage the employment of specialists","B":"encourage competition","C":"discourage the use of each other's bye-product","D":"create a monopoly"},"answer":"D","explanation":"Firms often merge to create a monopoly, which allows them to dominate the market and reduce competition. This can lead to increased market power and the ability to set prices without the pressure of competitors. Mergers can also lead to economies of scale and increased efficiency.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>63","subject":"Commerce","year":"1994","type":"Objective","topic":"STOCK EXCHANGE : TYPES OF SECURITIES","question":"Those who buy and sell shares on their own account in the stock exchange are","images":[],"options":{"A":"underwriters","B":"brokers","C":"clerks","D":"jobbers"},"answer":"D","explanation":"Those who buy and sell shares on their own account in the stock exchange are referred to as 'jobbers'. Jobbers act as market makers, providing liquidity to the market by buying and selling shares for their own profit, as opposed to brokers who act on behalf of clients.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>64","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE ASSOCIATION : MEANING & FUNCTIONS","question":"Which of the following is not a trade association?","images":[],"options":{"A":"Nigeria Union of Teachers","B":"Nigerian Medical Association","C":"Patent Medicine dealers Association","D":"Motor Spare Parts Dealers Union"},"answer":"A","explanation":"The Nigeria Union of Teachers is not a trade association; it is a professional association that represents teachers. Trade associations typically represent businesses or industries, while professional associations represent individuals in a profession.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>65","subject":"Commerce","year":"1994","type":"Objective","topic":"MONEY : QUALITIES OF MONEY","question":"Which of the following must any form of money possess in order to be generally acceptable?","images":[],"options":{"A":"Divisibility","B":"Mobility","C":"Durability","D":"Legality"},"answer":"D","explanation":"For any form of money to be generally acceptable, it must possess 'Legality'. This means that the money must be recognized by the government as a valid medium of exchange. While other characteristics like divisibility and durability are important, legality is essential for acceptance in transactions.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>66","subject":"Commerce","year":"1994","type":"Objective","topic":"PRODUCTION : FACTORS OF PRODUCTION","question":"Which of the following is not a factor of production?","images":[],"options":{"A":"Labour","B":"Profit","C":"Capital","D":"Land"},"answer":"B","explanation":"Profit is not a factor of production. The factors of production are typically classified as land, labor, capital, and enterprise. Profit is the financial gain obtained after all expenses are subtracted from revenue, and it is not a resource used in the production process.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>67","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"Which of the following is not a source of short-term capital?","images":[],"options":{"A":"Trade credit","B":"Overdraft","C":"Bonus issue","D":"Discounting bills"},"answer":"C","explanation":"A bonus issue is not a source of short-term capital. It refers to the issuance of additional shares to existing shareholders, which does not provide immediate cash flow. In contrast, trade credit, overdrafts, discounting bills, and money market instruments are all sources of short-term capital.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>68","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"Debentures differ from shares in that","images":[],"options":{"A":"they form part of the capital of the business","B":"rewards are usually paid out of profit","C":"ownership is open to the public","D":"they are usually secured by  a charge on the company assets"},"answer":"D","explanation":"Debentures differ from shares in that they are usually secured by a charge on the company assets. Debentures are a form of debt financing, meaning they represent a loan made to the company, while shares represent ownership in the company. The rewards for debenture holders are fixed interest payments, which are paid before any profits are distributed to shareholders.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>69","subject":"Commerce","year":"1994","type":"Objective","topic":"MONEY : FUNCTIONS OF MONEY","question":"Which of the following is responsible for carrying out the monetary policy of a country?","images":[],"options":{"A":"The Ministry of Finance","B":"International Monetary Fund","C":"Internal Revenue Board","D":"The Centrak Bank"},"answer":"D","explanation":"The Central Bank is responsible for carrying out the monetary policy of a country. It manages the country's currency, money supply, and interest rates, and it plays a crucial role in stabilizing the economy. Other options listed do not have the primary responsibility for monetary policy.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>70","subject":"Commerce","year":"1994","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF TRADE","question":"Which of the following indicates that manufacturer from whom goods are to be bought?","images":[],"options":{"A":"Open indent","B":"Closed indent","C":"Consignment note","D":"Export invoice"},"answer":"A","explanation":"An open indent indicates the manufacturer from whom goods are to be bought. It is a document that specifies the details of the order and the supplier. Closed indent, consignment note, export invoice, and certificate of origin serve different purposes in the trade process.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>71","subject":"Commerce","year":"1994","type":"Objective","topic":"STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS","question":"When applications are received for more shares that are offered for sale, the issue is said to be","images":[],"options":{"A":"under subscribed","B":"selling above par","C":"selling below par","D":"over subscribed"},"answer":"D","explanation":"When applications are received for more shares than are offered for sale, the issue is termed 'over subscribed'. This means that the demand for shares exceeds the supply, leading to a situation where investors may not receive the full amount of shares they applied for.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>72","subject":"Commerce","year":"1994","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"Which of the following is not a branch of commerce?","images":[],"options":{"A":"Trade","B":"Transport","C":"Warehousing","D":"Production"},"answer":"D","explanation":"Production is not considered a branch of commerce. Commerce primarily involves the activities of trade, transport, warehousing, and banking, which facilitate the buying and selling of goods and services. Production, on the other hand, refers to the creation of goods and services.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>73","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA","question":"Which of the following is most suitable for demonstrating the features of a new product?","images":[],"options":{"A":"Radio","B":"Newspaper","C":"Loud speaker","D":"Television"},"answer":"D","explanation":"Television is most suitable for demonstrating the features of a new product due to its visual and auditory capabilities, allowing for a more engaging presentation. It can showcase the product in action, highlight its features, and create a strong emotional connection with the audience.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>74","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : TYPES OF BANK","question":"Building societies secure the loans granted to customers by","images":[],"options":{"A":"debentures","B":"stocks","C":"bonds","D":"mortgages"},"answer":"D","explanation":"Building societies secure the loans granted to customers by mortgages. A mortgage is a loan specifically used to purchase real estate, where the property itself serves as collateral for the loan. This means that if the borrower fails to repay, the building society can take possession of the property.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>75","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"A country resorts to counter trade when","images":[],"options":{"A":"it does not belong to any cartel organisation","B":"its imports are less than exports","C":"it wants to raise domestic production","D":"its foreign exchange is not sufficient to pay for import"},"answer":"D","explanation":"A country resorts to counter trade when its foreign exchange is not sufficient to pay for imports. Counter trade involves trading goods and services for other goods and services instead of using cash, which can help countries that face foreign exchange shortages to still engage in international trade.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>76","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"An actuary is the expert who","images":[],"options":{"A":"assesses the extent of risk sustained by an insured","B":"calculates the premium payable for an insurance policy","C":"brings clients to an insurance company for a commission","D":"undertakes to cover a risk or part of it"},"answer":"A","explanation":"An actuary is a professional who assesses the financial implications of risk and uncertainty. They use mathematics, statistics, and financial theory to study uncertain future events, particularly in the insurance and finance fields. Therefore, the correct option is that an actuary assesses the extent of risk sustained by an insured.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>77","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Which of the following is common to ocean liner and train?","images":[],"options":{"A":"Move on rails","B":"Form of land transport","C":"Travel according to schedule","D":"Fitte with long coaches"},"answer":"C","explanation":"Both ocean liners and trains operate on schedules, which means they have set times for departures and arrivals. This is a common characteristic that allows passengers to plan their travel accordingly. The other options do not apply to both modes of transport.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>78","subject":"Commerce","year":"1994","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING","question":"Which of the following is used when goods are sent through  a common carrier?","images":[],"options":{"A":"Receipt","B":"Delivery note","C":"Proforma invoice","D":"Consignment note"},"answer":"D","explanation":"A consignment note is a document that accompanies goods when they are sent through a common carrier. It serves as a receipt for the goods and provides details about the shipment. The other options do not specifically relate to the process of sending goods via a common carrier.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>79","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"The issue of shares to interested existing shareholders in proportion to their holding is known as","images":[],"options":{"A":"private placing","B":"rights issue","C":"bonus issue","D":"issue by prospectus"},"answer":"B","explanation":"A rights issue is a way for companies to raise capital by giving existing shareholders the right to purchase additional shares in proportion to their existing holdings. This allows shareholders to maintain their ownership percentage in the company. The other options do not accurately describe this process.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>80","subject":"Commerce","year":"1994","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT","question":"Which of the following is not an essential element of valid contract?","images":[],"options":{"A":"Offer","B":"Acceptance","C":"Legal","D":"Compensation"},"answer":"D","explanation":"Compensation is not an essential element of a valid contract. The essential elements of a valid contract typically include offer, acceptance, legal purpose, and consideration. Compensation may be a result of a contract but is not a necessary element for the contract to be valid.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>81","subject":"Commerce","year":"1994","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS","question":"Which of the following provides that the cash price of all goods be clearly shown?","images":[],"options":{"A":"Sale of Goods Act","B":"Fair Trading Act","C":"Food and Drugs Act","D":"Hire Purchase Act"},"answer":"B","explanation":"The Fair Trading Act is designed to protect consumers by ensuring that they are provided with accurate information about goods and services, including the requirement that the cash price of all goods be clearly shown.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>82","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"Which of the following categories of workers does not provide direct services?","images":[],"options":{"A":"Teachers","B":"Doctors","C":"Wholesalers","D":"Musicians"},"answer":"C","explanation":"Wholesalers do not provide direct services to consumers; instead, they sell goods in bulk to retailers or other businesses, acting as intermediaries in the supply chain.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>83","subject":"Commerce","year":"1994","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Places as a component of the marketing mix is the same as","images":[],"options":{"A":"market centre","B":"central location","C":"distribution","D":"communication"},"answer":"C","explanation":"In the marketing mix, 'places' refers to the distribution channels through which products reach consumers. This includes the locations where products are sold and how they are delivered to the market.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>84","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT","question":"Which of the following is not a reason for Stock  Control?","images":[],"options":{"A":"check pilfering of goods","B":"distinguish a firm's stock of goods from others","C":"meet customer's demand at all times","D":"know the amount of goods in stock at any point in time"},"answer":"B","explanation":"Distinguishing a firm's stock of goods from others is not a primary reason for stock control. Stock control mainly focuses on managing inventory levels, preventing loss, and ensuring that customer demand is met.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>85","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES","question":"The activities of competitors in the market are part of the","images":[],"options":{"A":"technological environment","B":"social environment","C":"legal environment","D":"economic environment"},"answer":"D","explanation":"The activities of competitors in the market are part of the economic environment, as they influence market dynamics, pricing strategies, and overall competition within the industry.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>86","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"The amount of capital supplied by the owners of a company is known as","images":[],"options":{"A":"loan capital","B":"working capital","C":"capital employed","D":"share capital"},"answer":"D","explanation":"The amount of capital supplied by the owners of a company is known as 'share capital'. Share capital represents the funds raised by a company in exchange for shares of stock. This is the money that the owners (shareholders) invest in the company, which is used for business operations and growth.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>87","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"Which of the following takes possession of goods and sells in his own name?","images":[],"options":{"A":"Factor","B":"Del credere agent","C":"Auctioneer","D":"Broker"},"answer":"A","explanation":"A 'Factor' is an agent who takes possession of goods and sells them in his own name. Factors typically buy goods from manufacturers and sell them to retailers, taking on the risk of selling the goods. This distinguishes them from brokers, who act as intermediaries without taking possession.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>88","subject":"Commerce","year":"1994","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES","question":"A patent is usually granted to an individuals whose work","images":[],"options":{"A":"can be linked with an existing artistic work","B":"is a new invention","C":"took many years to accomplish","D":"is a transfer from foreign invention"},"answer":"B","explanation":"A patent is usually granted for 'a new invention'. This legal protection allows the inventor exclusive rights to their invention for a certain period, preventing others from making, using, or selling the invention without permission. The essence of a patent is that it must be novel and non-obvious.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1994>89","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES","question":"Which of the following is not a tool for sales promotion?","images":[],"options":{"A":"Advertising","B":"Free samples","C":"Personal selling","D":"Publicity"},"answer":"A","explanation":"Advertising is not typically considered a tool for sales promotion; rather, it is a broader marketing strategy aimed at creating awareness and interest in a product or service. Sales promotion tools are more direct incentives to encourage immediate sales, such as free samples or discounts.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>90","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : PRINCIPLES","question":"Business risks that can be insured against include    I. imitation of a company's product  II. damages caused by the use of a company's product  III. changes in fashion  IV. damages caused by fire  V. damages caused by flood","images":[],"options":{"A":"I, II and V only","B":"II and IV only","C":"III and IV only","D":"IV and V only"},"answer":"D","explanation":"Business risks that can be insured against include damages caused by fire and damages caused by flood. These are insurable risks because they can be quantified and are typically covered by property insurance policies. In contrast, risks like imitation of a product or changes in fashion are not insurable as they are more related to market dynamics and competition.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1994>91","subject":"Commerce","year":"1994","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"A group of firms that agree to operate a common price is a","images":[],"options":{"A":"cartel","B":"customs union","C":"price ring","D":"holding company"},"answer":"A","explanation":"A cartel is a group of firms that agree to coordinate their pricing and production decisions to maximize their collective profits. This is done to reduce competition among the member firms and can lead to higher prices for consumers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>92","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"It is important for banks to maintain a high percentage of cash ratio in order to","images":[],"options":{"A":"make more profits","B":"invest in long term ventures","C":"encourage more cash deposits","D":"meet their customers demand for cash at any time"},"answer":"D","explanation":"Banks maintain a high cash ratio to ensure they can meet customer demands for cash at any time. This is crucial for maintaining liquidity and trust in the banking system, allowing customers to withdraw their deposits whenever needed.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>93","subject":"Commerce","year":"1994","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION","question":"Which of the following does not aim at protecting the consumer?","images":[],"options":{"A":"Hire Purchase Act","B":"Weight and Measure Act","C":"Indigenisation Act","D":"Food and Drugs Act"},"answer":"C","explanation":"The Indigenisation Act does not primarily aim at protecting consumers; rather, it focuses on promoting local ownership and control of businesses. In contrast, the other acts listed are specifically designed to protect consumer rights and interests.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>94","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES","question":"Small unit shops continue to exist inspite of stiff competition by large stores because they","images":[],"options":{"A":"are located near large shops","B":"employ travelling salesmen","C":"stock one line of goods","D":"maintain personal contact with their customers"},"answer":"D","explanation":"Small unit shops often maintain personal contact with their customers, which helps build loyalty and repeat business. This personal touch can be a significant advantage over larger stores, which may not offer the same level of customer service.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>95","subject":"Commerce","year":"1994","type":"Objective","topic":"ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE","question":"Which of the following is primarily responsible for projecting the image of a company?","images":[],"options":{"A":"Sales Department","B":"Personnel Department","C":"Public Relations Department","D":"Accounts Department"},"answer":"C","explanation":"The Public Relations Department is primarily responsible for projecting the image of a company. This department manages communication with the public and media, shaping how the company is perceived and maintaining its reputation.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>96","subject":"Commerce","year":"1994","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"Which of the following is not a barrier to smooth trade among ECOWAS member nations?","images":[],"options":{"A":"Differences in currencies and languages","B":"Establishment of a common tariff","C":"Constant changes in government","D":"Political and ideological differences"},"answer":"B","explanation":"The establishment of a common tariff is not a barrier to trade; rather, it is a measure that facilitates trade among member nations by standardizing tariffs and reducing trade barriers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>97","subject":"Commerce","year":"1994","type":"Objective","topic":"MONEY : QUALITIES OF MONEY","question":"Which of the following features of money facilitates small transactions?","images":[],"options":{"A":"Portability","B":"Durability","C":"Divisibility","D":"Scarcity"},"answer":"C","explanation":"Divisibility is a feature of money that allows it to be broken down into smaller units, making it easier to conduct small transactions. This means that money can be divided into smaller denominations to accommodate various transaction sizes.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1994>98","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Which of the following widens the market for goods?","images":[],"options":{"A":"Warehousing","B":"Transport","C":"Insurance","D":"Banking"},"answer":"B","explanation":"Transport widens the market for goods by enabling the movement of products from one location to another, thus allowing sellers to reach a larger customer base beyond their immediate vicinity.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>99","subject":"Commerce","year":"1994","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Which of the following is centrally controlled?","images":[],"options":{"A":"Multiple shop","B":"Mobile shop","C":"Department store","D":"Supermarket"},"answer":"C","explanation":"A department store is centrally controlled as it operates under a single management structure, unlike multiple shops or mobile shops which may operate independently.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1994>100","subject":"Commerce","year":"1994","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : SERVICES","question":"The fastest means of sending written information to a parent company abroad is the","images":[],"options":{"A":"telegram","B":"telephone","C":"telex","D":"courier service"},"answer":"D","explanation":"Courier service is the fastest means of sending written information to a parent company abroad, as it provides expedited delivery options compared to other methods like telegrams or express letters.","marks":"1","difficulty":"2"}];